using System.Collections;
using System.Runtime.InteropServices;

class EnvVarCheck
{
    // .NET 9 breaking change: on Linux, GetEnvironmentVariable returns null
    // for empty env vars (previously returned ""). Use P/Invoke to libc
    // getenv to preserve the "not set" vs "explicitly empty" distinction.
    [DllImport("libc", EntryPoint = "getenv", CharSet = CharSet.Ansi)]
    private static extern IntPtr NativeGetEnv(string name);

    void CheckFlag()
    {
        // On Linux, set via: export MY_FLAG=""
        if (RuntimeInformation.IsOSPlatform(OSPlatform.Linux))
        {
            IntPtr ptr = NativeGetEnv("MY_FLAG");
            if (ptr == IntPtr.Zero)
            {
                Console.WriteLine("MY_FLAG not set, using default");
            }
            // ptr != IntPtr.Zero means the var exists (possibly empty)
        }
        else
        {
            var val = Environment.GetEnvironmentVariable("MY_FLAG");
            if (val == null)
            {
                Console.WriteLine("MY_FLAG not set, using default");
            }
        }
    }
}

